import './modules/extensions.mjs';
import { auth, db } from './firebase-config.js';
import { onAuthStateChanged, signInAnonymously } from "firebase/auth";
import { doc, onSnapshot } from "firebase/firestore";
import { getPermisosUsuario, migrateConductoresToPublicadores } from './data/firestore-services.js';
import { initTheme, createThemeToggle } from './modules/utils/theme-manager.js';
import { initUpdateManager } from './modules/utils/update-manager.js';
import { moduleRegistry } from './modules/utils/module-registry.js';
import { XolvyAdaptive } from './modules/utils/adaptive.js';
import { VisualEngine } from './modules/utils/visual-engine.js';

// Initialize Visual Ecosystem
VisualEngine.applyGlobalEcosystem();

// Initialize Module Registry
moduleRegistry.init();

// The version is injected by Vite at build time (Core Shell Version)
const APP_VERSION = __APP_VERSION__;

// --- XOLVY MODULAR: MICRO-MODULE ENGINE ---
const dynamicModules = import.meta.glob('./modules/**/*.js');

async function loadModule(moduleName, basePath) {
    return moduleRegistry.loadModule(moduleName, basePath, dynamicModules);
}

// Shell View Accessors
const loadLogin = async () => (await loadModule('login', './modules/login.js')).renderLogin;
const loadAdmin = async () => (await loadModule('admin', './modules/admin-dashboard.js')).renderAdminDashboard;
const loadConductor = async () => (await loadModule('conductor', './modules/conductor-dashboard.js')).renderConductorDashboard;


// --- DIFFUSION LISTENER ---
const initDiffusionListener = () => {
    onSnapshot(doc(db, "configuracion", "diffusion_active"), (docSnap) => {
        let banner = document.getElementById('global-diffusion-banner');
        if (docSnap.exists() && docSnap.data().active) {
            const data = docSnap.data();
            if (!banner) {
                banner = document.createElement('div');
                banner.id = 'global-diffusion-banner';
                document.body.prepend(banner);
            }
            const bgColor = data.type === 'urgent' ? 'from-red-600 to-red-800' : 'from-blue-600 to-blue-800';
            banner.className = `w-full bg-gradient-to-r ${bgColor} text-white p-4 flex items-center justify-center gap-4 sticky top-0 z-[100] shadow-2xl`;
            banner.innerHTML = `<span>­ƒôó</span> <div class="flex-1 text-center font-black uppercase text-xs">${data.content}</div>`;
        } else {
            if (banner) banner.remove();
        }
    });
};

// Initialization
document.addEventListener('DOMContentLoaded', async () => {
    const appContainer = document.getElementById('app-container');

    initTheme();
    initUpdateManager();
    initDiffusionListener();
    XolvyAdaptive.init();

    const handleAuthChange = async (user) => {
        try {
            appContainer.innerHTML = '<div class="flex items-center justify-center min-h-screen"><div class="w-12 h-12 border-4 border-primary/20 border-t-primary rounded-full animate-spin"></div></div>';
            const path = window.location.pathname;

            if (user) {
                if (user.isAnonymous) {
                    const storedRole = localStorage.getItem('demo_role');
                    const storedName = localStorage.getItem('selected_conductor_name');
                    if (storedRole === 'Conductor') {
                        if (!path.startsWith('/conductores')) window.history.replaceState({}, '', '/conductores');
                        const render = await loadConductor();
                        render(appContainer, storedName || 'Conductor', APP_VERSION, storedRole);
                        return;
                    }
                }

                const permisos = await getPermisosUsuario(user.email);
                let role = permisos?.role || localStorage.getItem('demo_role');

                if (!role) {
                    await auth.signOut();
                    const render = await loadLogin();
                    render(appContainer, APP_VERSION);
                    return;
                }

                const isAdmin = (role === 'Administrador' || role === 'SuperAdmin');
                if (isAdmin && !path.startsWith('/conductores')) {
                    const subPath = path.split('/')[2] || 'dashboard';
                    const urlToTab = { 'territorios': 'casa-en-casa', 'predicacion': 'predicacion', 'telefonos': 'telefonos', 'config': 'config' };
                    const tabId = urlToTab[subPath] || 'dashboard';
                    const render = await loadAdmin();
                    render(appContainer, APP_VERSION, tabId);
                } else {
                    if (!path.startsWith('/conductores')) window.history.replaceState({}, '', '/conductores');
                    const render = await loadConductor();
                    render(appContainer, user.email || 'Usuario', APP_VERSION, role);
                }
            } else {
                const render = await loadLogin();
                render(appContainer, APP_VERSION);
            }
        } catch (e) {
            console.error("­ƒÜÇ [Boot] Critical Auth/Render Error:", e);
            appContainer.innerHTML = `
                <div class="flex flex-col items-center justify-center min-h-screen p-10 text-center">
                    <div class="w-20 h-20 bg-rose-500/10 text-rose-500 rounded-3xl flex items-center justify-center text-3xl mb-6 shadow-xl"><i class="fas fa-biohazard animate-pulse"></i></div>
                    <h2 class="text-2xl font-black text-slate-800 dark:text-white uppercase tracking-tighter">Colapso del N├║cleo</h2>
                    <p class="text-slate-500 dark:text-slate-400 max-w-md mt-4 font-bold text-sm">Detectamos un error cr├¡tico que impide la conexi├│n con la base de datos. Esto suele ocurrir por corrupci├│n en el almacenamiento del navegador.</p>
                    <div class="bg-slate-50 dark:bg-black/20 p-6 rounded-2xl w-full max-w-lg mt-8 border border-slate-100 dark:border-white/5 text-left overflow-auto max-h-40">
                        <p class="text-[10px] font-mono text-rose-400 leading-relaxed">${e.message}</p>
                    </div>
                    <div class="flex flex-wrap justify-center gap-4 mt-10">
                        <button onclick="location.reload()" class="bg-indigo-600 hover:bg-indigo-500 text-white px-10 py-4 rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl shadow-indigo-500/20 transition-all active:scale-95">
                            <i class="fas fa-sync-alt mr-2"></i> Reintentar
                        </button>
                        <button onclick="window.repairSystem()" class="bg-slate-900 dark:bg-white/10 hover:bg-slate-800 text-white px-10 py-4 rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-xl transition-all active:scale-95 border border-white/5">
                            <i class="fas fa-tools mr-2"></i> Reparar N├║cleo
                        </button>
                    </div>
                </div>
            `;
        }
    };

    // --- HMS RE-RENDER LOGIC ---
    moduleRegistry.subscribe(async (moduleName, version) => {
        const path = window.location.pathname;

        // XOLVY UPDATES: Use the new discrete notification system
        const { notifyModuleUpdate, completeXolvyUpdate } = await import('./modules/utils/update-manager.js');
        notifyModuleUpdate(moduleName, version);

        // Define which sub-modules belong to which main view
        const conductorSubModules = ['availability', 'recursos', 'maps_explorer', 'rescue', 'phone_module', 'onboarding', 'weekly_program', 'program_views'];
        const adminSubModules = ['territories_view', 'public_view', 'phones_view', 'rules_view', 'analytics_view', 'reports_view'];

        // Determine if we should re-render
        const isConductorView = path.startsWith('/conductores');
        const isAdminView = !isConductorView && (localStorage.getItem('demo_role') === 'Administrador' || localStorage.getItem('demo_role') === 'SuperAdmin');

        const shouldRefreshConductor = isConductorView && (moduleName === 'conductor' || conductorSubModules.includes(moduleName));
        const shouldRefreshAdmin = isAdminView && (moduleName === 'admin' || adminSubModules.includes(moduleName));

        if (shouldRefreshConductor || shouldRefreshAdmin) {
            const user = auth.currentUser;

            // Xolvy Modular Rule 1.3: State Immortalization
            // Save scroll position before the re-render
            const uiState = {
                scroll: window.scrollY,
                module: moduleName,
                timestamp: Date.now()
            };
            sessionStorage.setItem('xolvy_hms_state', JSON.stringify(uiState));

            // Small delay to show the "Receiving" state in HUD
            setTimeout(() => {
                completeXolvyUpdate(moduleName, version);

                // Targeted refresh or full re-auth
                if (shouldRefreshConductor && window.refreshConductorView) {
                    window.refreshConductorView().then(() => { restoreState(); XolvyAdaptive.refresh(); });
                } else if (shouldRefreshAdmin && window.refreshAdminView) {
                    window.refreshAdminView().then(() => { restoreState(); XolvyAdaptive.refresh(); });
                } else {
                    handleAuthChange(user).then(() => { restoreState(); XolvyAdaptive.refresh(); });
                }
            }, 2000);
        } else {
            // Not in the relevant view, just finish the HUD
            setTimeout(() => {
                completeXolvyUpdate(moduleName, version);
            }, 2500);
        }
    });

    const restoreState = () => {
        const saved = sessionStorage.getItem('xolvy_hms_state');
        if (saved) {
            const { scroll } = JSON.parse(saved);
            window.scrollTo({ top: scroll, behavior: 'smooth' });
            sessionStorage.removeItem('xolvy_hms_state');
        }
    };

    // Xolvy Data Shield: Cache Burster on version change
    const lastVer = localStorage.getItem('last_app_version');
    if (lastVer !== APP_VERSION) {
        console.log(`Ô£¿ Version Upgrade: ${lastVer} -> ${APP_VERSION}. Purging caches.`);
        const { clearServiceCache } = await import('./data/firestore-services.js');
        clearServiceCache();
        localStorage.setItem('last_app_version', APP_VERSION);
    }

    migrateConductoresToPublicadores();

    onAuthStateChanged(auth, handleAuthChange);

    document.addEventListener('demo-login', async (e) => {
        const { email, role } = e.detail;
        localStorage.setItem('demo_role', role);
        localStorage.setItem('selected_conductor_name', email);
        await signInAnonymously(auth);
    });
});

import { db } from '../../firebase-config.js';
import { collection, getDocs, doc, setDoc, writeBatch, Timestamp } from "firebase/firestore";

export const restoreSystemBackup = async (data, onProgress) => {
    if (!data) throw new Error("No data provided for restore");
    const collections = [
        { key: 'territorios', name: 'territorios' },
        { key: 'conductores', name: 'conductores' },
        { key: 'telefonos', name: 'telefonos' },
        { key: 'publicadores', name: 'publicadores' },
        { key: 'historial', name: 'historial_territorios' }
    ];
    let totalOps = 0;
    collections.forEach(c => { if (data[c.key]) totalOps += data[c.key].length; });
    if (data.config) totalOps += 1;
    if (data.programa) totalOps += 1;

    let executedOps = 0;
    const reportProgress = (msg) => {
        if (onProgress) onProgress(msg, Math.floor((executedOps / totalOps) * 100));
    };

    for (const colDef of collections) {
        const items = data[colDef.key];
        if (!items || !Array.isArray(items)) continue;
        reportProgress(`Restaurando ${colDef.key}...`);
        for (let i = 0; i < items.length; i += 500) {
            const batch = writeBatch(db);
            const chunk = items.slice(i, i + 500);
            chunk.forEach(item => {
                const { id, ...cleanData } = item;
                const docRef = id ? doc(db, colDef.name, id) : doc(collection(db, colDef.name));
                batch.set(docRef, cleanData, { merge: true });
                executedOps++;
            });
            await batch.commit();
        }
    }
    if (data.config) {
        const { id, ...configData } = data.config;
        await setDoc(doc(db, "configuracion", id || "general"), configData, { merge: true });
        executedOps++;
    }
    return executedOps;
};

import { db } from '../../firebase-config.js';
import { doc, getDoc, setDoc, updateDoc, Timestamp } from "firebase/firestore";

// --- CONFIGURACI├ôN GLOBAL ---

export const getGlobalSettings = async () => {
    try {
        const docRef = doc(db, "configuracion", "global_settings");
        const snap = await getDoc(docRef);
        if (snap.exists()) {
            return snap.data();
        }
        return {
            expiration_days: 120,
            max_active_assignments: 0,
            theme_color: 'teal',
            congregation_name: 'Mi Congregaci├│n',
            modules: {
                phone_preaching: true,
                public_preaching: true
            }
        };
    } catch (e) {
        console.error("Error fetching global settings:", e);
        return null;
    }
};

export const saveGlobalSettings = async (settings) => {
    try {
        await setDoc(doc(db, "configuracion", "global_settings"), settings, { merge: true });
        return true;
    } catch (e) {
        console.error("Error saving global settings:", e);
        throw e;
    }
};

// --- DIFFUSION SYSTEM ---
export const saveDiffusionMessage = async (message, type = 'info') => {
    try {
        const docRef = doc(db, "configuracion", "diffusion_active");
        if (message) {
            await setDoc(docRef, {
                content: message,
                type: type,
                timestamp: Timestamp.now(),
                active: true
            });
        } else {
            await updateDoc(docRef, { active: false });
        }
        return true;
    } catch (e) {
        console.error("Error saving diffusion message:", e);
        throw e;
    }
};

export const getDiffusionMessage = async () => {
    try {
        const docRef = doc(db, "configuracion", "diffusion_active");
        const snap = await getDoc(docRef);
        if (snap.exists() && snap.data().active) {
            return snap.data();
        }
        return null;
    } catch (e) {
        console.error("Error fetching diffusion message:", e);
        return null;
    }
};

export const getGroupsConfig = async () => {
    try {
        const docRef = doc(db, "configuracion", "grupos_config");
        const snap = await getDoc(docRef);
        return snap.exists() ? snap.data().grupos || [] : [];
    } catch (e) {
        console.error("Error fetching groups config:", e);
        return [];
    }
};

export const saveGroupsConfig = async (grupos) => {
    try {
        const docRef = doc(db, "configuracion", "grupos_config");
        await setDoc(docRef, { grupos });
        return true;
    } catch (e) {
        console.error("Error saving groups config:", e);
        throw e;
    }
};

export const getConfiguracion = async () => {
    try {
        const docRef = doc(db, "configuracion", "general");
        const snap = await getDoc(docRef);
        return snap.exists() ? snap.data() : {};
    } catch (e) {
        console.error("Error fetching general config:", e);
        return {};
    }
};

export const saveConfiguracion = async (config) => {
    try {
        await setDoc(doc(db, "configuracion", "general"), config, { merge: true });
        return true;
    } catch (e) {
        console.error("Error saving general config:", e);
        throw e;
    }
};

export const getSystemVersion = async () => {
    try {
        const docRef = doc(db, "configuracion", "system_status");
        const snap = await getDoc(docRef);
        return snap.exists() ? snap.data().current_version : "0.0.0";
    } catch (e) {
        console.error("Error fetching system version:", e);
        return "0.0.0";
    }
};

export const setSystemVersion = async (version, force = true) => {
    try {
        const docRef = doc(db, "configuracion", "system_status");
        await setDoc(docRef, {
            current_version: version,
            last_update: Timestamp.now()
        }, { merge: true });
        return true;
    } catch (e) {
        console.error("Error setting system version:", e);
        throw e;
    }
};

import { db } from '../../firebase-config.js';
import { collection, query, where, getDocs, doc, writeBatch, deleteDoc, setDoc, Timestamp } from "firebase/firestore";
import { ServiceCache } from './base-service.js';

export const runSystemDiagnosticsAndRepair = async (onProgress) => {
    const report = {
        rebuiltHistory: 0, fixedPhones: 0, fixedTerritories: 0, syncPersonnel: 0, details: []
    };
    const reportProgress = (msg, pc) => { if (onProgress) onProgress(msg, pc); };

    reportProgress("­ƒöì Escaneando integridad de territorios...", 30);
    const terrSnap = await getDocs(collection(db, "territorios"));
    const terrBatch = writeBatch(db);
    let terrBatchCount = 0;

    for (const d of terrSnap.docs) {
        const t = d.data();
        let updates = {};
        let dirty = false;

        if (t.estado === 'Asignado' && !t.asignado_a) {
            updates.estado = 'Disponible'; updates.fecha_asignacion = null; updates.turno = null; dirty = true;
            report.details.push(`Territorio ${t.numero}: Corregido estado 'Asignado' sin conductor -> Disponible`);
        }
        if (t.estado === 'Disponible' && (t.asignado_a || t.fecha_asignacion)) {
            updates.asignado_a = null; updates.fecha_asignacion = null; updates.turno = null; dirty = true;
            report.details.push(`Territorio ${t.numero}: Limpiado conductor en territorio 'Disponible'`);
        }
        if (!['Disponible', 'Asignado', 'Extraviado', 'Predicado', 'Pendiente'].includes(t.estado)) {
            updates.estado = 'Disponible'; dirty = true;
            report.details.push(`Territorio ${t.numero}: Estado inv├ílido '${t.estado}' -> Disponible`);
        }
        if (String(t.numero) !== String(t.numero).trim()) {
            updates.numero = String(t.numero).trim(); dirty = true;
            report.details.push(`Territorio ${t.numero}: N├║mero normalizado`);
        }

        if (dirty) {
            terrBatch.update(d.ref, updates);
            report.fixedTerritories++; terrBatchCount++;
            if (terrBatchCount >= 500) { await terrBatch.commit(); terrBatchCount = 0; }
        }
    }
    if (terrBatchCount > 0) await terrBatch.commit();

    reportProgress("­ƒôí Escaneo profundo de base de datos telef├│nica...", 45);
    const allPhones = await getDocs(collection(db, "telefonos"));
    const allPubs = await getDocs(collection(db, "publicadores"));
    const pubsMap = {};
    allPubs.forEach(d => {
        const p = d.data();
        pubsMap[d.id] = p.nombre;
        pubsMap[p.nombre] = d.id;
    });

    let phoneBatch = writeBatch(db);
    let phoneBatchCount = 0;
    for (const d of allPhones.docs) {
        const t = d.data();
        let updates = {};
        let dirty = false;
        const status = (t.estado || '').trim().toLowerCase();

        if (t.asignado_a === 'Usuario' || t.publicador_asignado === 'Usuario') {
            if (pubsMap[t.publicador_asignado]) {
                updates.asignado_a = pubsMap[t.publicador_asignado]; dirty = true;
            } else {
                updates.asignado_a = null; updates.publicador_asignado = null; updates.estado = 'Sin asignar'; dirty = true;
            }
        }
        if (dirty) {
            phoneBatch.update(d.ref, updates);
            report.fixedPhones++; phoneBatchCount++;
            if (phoneBatchCount >= 500) {
                await phoneBatch.commit();
                phoneBatch = writeBatch(db);
                phoneBatchCount = 0;
            }
        }
    }
    if (phoneBatchCount > 0) await phoneBatch.commit();

    reportProgress("­ƒæÑ Sincronizando directorio personal...", 95);
    const pubBatch = writeBatch(db);
    let pubCount = 0;
    allPubs.forEach(d => {
        const p = d.data();
        if (!p.modulos || p.modulos.telefonos !== true) {
            pubBatch.update(d.ref, { 'modulos.telefonos': true });
            pubCount++;
        }
    });
    if (pubCount > 0) { await pubBatch.commit(); report.syncPersonnel = pubCount; }

    reportProgress("Ô£¿ Limpieza profunda completada.", 100);
    return report;
};

export const clearAllCurrentData = async (onProgress) => {
    const reportProgress = (msg, pc) => { if (onProgress) onProgress(msg, pc); };
    // Implementation of masterResetAssignments logic
    const terrSnap = await getDocs(collection(db, "territorios"));
    const terrBatch = writeBatch(db);
    let tCount = 0;
    terrSnap.forEach(d => {
        const t = d.data();
        if (t.estado === 'Asignado' || t.asignado_a || t.fecha_asignacion) {
            terrBatch.update(d.ref, { estado: 'Disponible', asignado_a: null, fecha_asignacion: null, turno: null });
            tCount++;
        }
    });
    if (tCount > 0) await terrBatch.commit();
    const progSnap = await getDocs(collection(db, "programa_semanal"));
    for (const d of progSnap.docs) await deleteDoc(d.ref);
    return { territoriesReset: tCount, programsDeleted: progSnap.docs.length };
};

export const masterResetAssignments = clearAllCurrentData;

import { db } from '../../firebase-config.js';
import { collection, getDocs, addDoc, deleteDoc, doc, updateDoc, query, where, getDoc, orderBy, limit, Timestamp, writeBatch, runTransaction, arrayUnion } from "firebase/firestore";
import { ServiceCache } from './base-service.js';

const COL_TELEFONOS = "telefonos";

export const getMisTelefonos = async (conductorQuery) => {
    // Return all for client-side filtering as dataset is small or implement query if needed
    const querySnapshot = await getDocs(collection(db, COL_TELEFONOS));
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
};

export const getTelefonosParaSesion = async (conductorName) => {
    try {
        const phoneCol = collection(db, COL_TELEFONOS);
        const qSession = query(phoneCol, where("estado", "in", ["En Sesi├│n", "Revisita"]));
        const snap = await getDocs(qSession);
        const data = snap.docs.map(doc => ({ id: doc.id, ...doc.data() }));

        if (conductorName) {
            const qAssigned = query(phoneCol, where("asignado_a", "==", conductorName));
            const snapAssigned = await getDocs(qAssigned);
            snapAssigned.forEach(d => {
                if (!data.find(existing => existing.id === d.id)) {
                    data.push({ id: d.id, ...d.data() });
                }
            });
        }
        return data;
    } catch (e) {
        console.error("Error fetching session phones:", e);
        return [];
    }
};

export const getTelefonos = async () => {
    const querySnapshot = await getDocs(collection(db, COL_TELEFONOS));
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
};

export const addTelefono = async (telefono) => {
    await addDoc(collection(db, COL_TELEFONOS), telefono);
};

export const solicitarNumeros = async (cantidad = 30, conductorName = null) => {
    try {
        const result = await runTransaction(db, async (transaction) => {
            const now = new Date();
            const sixMonthsAgo = new Date();
            sixMonthsAgo.setMonth(now.getMonth() - 6);

            const q = query(collection(db, COL_TELEFONOS),
                where("estado", "==", "Sin asignar"),
                limit(cantidad * 10)
            );

            const snapshot = await getDocs(q);
            const selectedDocs = [];
            let count = 0;

            for (const d of snapshot.docs) {
                if (count >= cantidad) break;
                const data = d.data();
                if (data.publicador_asignado || data.asignado_a || data.estado === 'En Sesi├│n') continue;
                if (data.ultimo_estado === 'No llamar') {
                    const lastDate = data.fecha_ultimo_estado ? new Date(data.fecha_ultimo_estado) : new Date(0);
                    if (lastDate > sixMonthsAgo) continue;
                }
                selectedDocs.push(d);
                count++;
            }

            if (selectedDocs.length === 0) return 0;

            selectedDocs.forEach(d => {
                transaction.update(d.ref, {
                    estado: 'En Sesi├│n',
                    publicador_asignado: null,
                    asignado_a: null,
                    fecha_asignacion: now.toISOString(),
                    solicitado_por: conductorName
                });
            });

            return selectedDocs.length;
        });

        if (result === 0) {
            const resetDone = await checkAndResetTelephoneCycle(true);
            if (resetDone) return await solicitarNumeros(cantidad, conductorName);
        }

        ServiceCache.clear("telefonos");
        return result;
    } catch (error) {
        console.error("Error in solicitarNumeros transaction:", error);
        throw error;
    }
};

export const checkAndResetTelephoneCycle = async (forceRequested = false) => {
    try {
        const snapshot = await getDocs(collection(db, COL_TELEFONOS));
        const total = snapshot.docs.length;
        if (total === 0) return false;

        const processedRecords = snapshot.docs.filter(d => {
            const data = d.data();
            const hasStatus = data.estado && !['Sin asignar', 'En Sesi├│n'].includes(data.estado);
            const isRequested = !!data.solicitado_por;
            return hasStatus || isRequested;
        });

        if (processedRecords.length >= total || forceRequested) {
            if (forceRequested) {
                const anyAvailable = snapshot.docs.some(d => {
                    const data = d.data();
                    return data.estado === 'Sin asignar' && (data.solicitado_por === null || data.solicitado_por === undefined);
                });
                if (anyAvailable) return false;
            }

            let batch = writeBatch(db);
            let operationCount = 0;
            const now = new Date().toISOString();

            for (const d of snapshot.docs) {
                const data = d.data();
                const currentStatus = data.estado;
                let updateData = null;

                if (!currentStatus || ['Contestaron', 'No contestan', 'Colgaron', 'Sin asignar'].includes(currentStatus)) {
                    updateData = {
                        estado: 'Sin asignar',
                        publicador_asignado: null,
                        asignado_a: null,
                        solicitado_por: null,
                        fecha_asignacion: null,
                        comentario: '',
                        ultima_observacion_ciclo: data.comentario || '',
                        fecha_ultimo_ciclo: now
                    };
                } else if (currentStatus === 'No llamar') {
                    updateData = {
                        ultimo_estado: 'No llamar',
                        estado: 'Sin asignar',
                        fecha_ultimo_estado: now,
                        publicador_asignado: null,
                        asignado_a: null,
                        solicitado_por: null
                    };
                }

                if (updateData) {
                    batch.update(doc(db, COL_TELEFONOS, d.id), updateData);
                    operationCount++;
                    if (operationCount >= 450) {
                        await batch.commit();
                        batch = writeBatch(db);
                        operationCount = 0;
                    }
                }
            }

            if (operationCount > 0) await batch.commit();
            return true;
        }
        return false;
    } catch (e) {
        console.error("Error in cycle reset:", e);
        return false;
    }
};

