import {
    getTerritorios, getConductores, getHistorialReport, getConfiguracion,
    assignTerritorio, returnTerritorio, getCampanas
} from '../../data/firestore-services.js';
import { showNotification } from '../utils/helpers.js';
import { UIHelpers, showModal, showCustomConfirm, showTerritorySelectionModal } from '../services/ui-helpers.js';

const { fmtDate } = UIHelpers;

let _globalTerritorios = [];
let _globalConductores = [];
let _globalConfig = {};
let _selectedIds = new Set();

export const renderAsignacionesView = async (container) => {
    const loadData = async () => {
        const [t, c, h, conf] = await Promise.all([
            getTerritorios(), getConductores(), getHistorialReport(), getConfiguracion()
        ]);

        // Xolvy Data Shield: Robust normalization & ghost filtering
        const normalizeT = (val) => String(val || '').trim();
        _globalTerritorios = t
            .filter(rec => {
                const hasNum = rec.numero && String(rec.numero).trim().length > 0;
                if (!hasNum) console.warn(`­ƒøí´©Å [Data Shield] Filtered ghost record: ${rec.id}`);
                return hasNum;
            })
            .map(rec => ({
                ...rec,
                numero: normalizeT(rec.numero),
                manzanas: String(rec.manzanas || '').replace(/Salmo/gi, 'Mz.').trim()
            }))
            .sort((a, b) => a.numero.localeCompare(b.numero, undefined, { numeric: true }));

        _globalConductores = c.filter(p => p.es_conductor).sort((a, b) => a.nombre.localeCompare(b.nombre));
        _globalConfig = conf;
        renderInternal();
    };

    const renderInternal = () => {
        container.innerHTML = `
            <div class="space-y-6 md:space-y-8 animate-fade-in px-1">
                <div class="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
                    <button id="hub-btn-assign" class="group relative bg-white dark:bg-white/5 overflow-hidden p-6 md:p-8 rounded-[2rem] border border-slate-200 dark:border-white/10 shadow-2xl transition-all hover:-translate-y-1">
                        <div class="flex items-center gap-6">
                            <div class="w-16 h-16 rounded-2xl bg-primary flex items-center justify-center text-3xl text-white shadow-lg shadow-primary/30"><i class="fas fa-plus"></i></div>
                            <div class="text-left">
                                <p class="text-[10px] font-black text-primary uppercase tracking-widest mb-1">Operaci├│n</p>
                                <p class="text-2xl font-black text-slate-800 dark:text-white uppercase">Nueva Asignaci├│n</p>
                            </div>
                        </div>
                    </button>
                    <button id="hub-btn-return" class="group relative bg-white dark:bg-white/5 overflow-hidden p-6 md:p-8 rounded-[2rem] border border-slate-200 dark:border-white/10 shadow-2xl transition-all hover:-translate-y-1">
                        <div class="flex items-center gap-6">
                            <div class="w-16 h-16 rounded-2xl bg-rose-500 flex items-center justify-center text-3xl text-white shadow-lg shadow-rose-500/30"><i class="fas fa-file-import"></i></div>
                            <div class="text-left">
                                <p class="text-[10px] font-black text-rose-500 uppercase tracking-widest mb-1">Recepci├│n</p>
                                <p class="text-2xl font-black text-slate-800 dark:text-white uppercase">Informar Completados</p>
                            </div>
                        </div>
                    </button>
                </div>

                <div id="assigns-grid" class="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 pb-20">
                    ${_globalTerritorios.map(t => {
            const isAssigned = t.estado === 'Asignado' || t.estado === 'Pendiente';
            return `
                        <div class="modern-card p-6 border-slate-100 dark:border-white/5 shadow-xl ${isAssigned ? 'bg-primary/5' : ''}">
                            <div class="flex justify-between items-start mb-4">
                                <span class="bg-primary/10 text-primary text-[10px] font-black px-2 py-1 rounded-lg uppercase tracking-widest">#${t.numero}</span>
                                <span class="text-[9px] font-black uppercase tracking-widest ${isAssigned ? 'text-primary' : 'text-slate-400 opacity-40'}">${t.estado}</span>
                            </div>
                            <h4 class="font-black text-lg text-slate-800 dark:text-white uppercase truncate mb-6">${t.asignado_a || 'Disponible'}</h4>
                            <div class="flex gap-2">
                                <button onclick="window.handleNewAssignment('${t.id}')" class="flex-1 py-3 bg-slate-100 dark:bg-white/5 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-primary hover:text-white transition-all">Gestionar</button>
                            </div>
                        </div>`;
        }).join('')}
                </div>
            </div>
        `;

        container.querySelector('#hub-btn-assign').onclick = () => window.handleNewAssignment();
        container.querySelector('#hub-btn-return').onclick = () => window.handleBulkReturn();
    };

    window.handleNewAssignment = async (editId = null) => {
        const item = editId ? _globalTerritorios.find(x => x.id === editId) : null;
        showModal(`
            <div class="p-8 space-y-6">
                <h3 class="text-xl font-black uppercase">Asignar Territorio</h3>
                <div class="space-y-4">
                    <div class="space-y-2">
                        <label class="text-[10px] font-black uppercase text-slate-400">Territorio(s)</label>
                        <input type="text" id="asig-terr-raw" value="${item ? item.numero : ''}" class="w-full p-4 bg-slate-100 dark:bg-white/5 rounded-xl font-bold" placeholder="Ejem: 10, 15, 20">
                    </div>
                    <div class="space-y-2">
                        <label class="text-[10px] font-black uppercase text-slate-400">Conductor</label>
                        <select id="asig-cond" class="w-full p-4 bg-slate-100 dark:bg-white/5 rounded-xl font-bold">
                            <option value="">Seleccionar Conductor...</option>
                            ${_globalConductores.map(c => `<option value="${c.nombre}">${c.nombre}</option>`).join('')}
                        </select>
                    </div>
                    <button id="btn-confirm-asig" class="w-full py-4 bg-primary text-white rounded-xl font-black uppercase tracking-widest">Confirmar</button>
                </div>
            </div>
        `, (modal) => {
            modal.querySelector('#btn-confirm-asig').onclick = async () => {
                const cond = modal.querySelector('#asig-cond').value;
                const raw = modal.querySelector('#asig-terr-raw').value;
                if (!cond || !raw) return showNotification("Faltan datos", "warning");

                const nums = raw.split(',').map(n => n.trim());
                for (const num of nums) {
                    const t = _globalTerritorios.find(x => String(x.numero) === num);
                    if (t) await assignTerritorio(t.id, cond, { estado: 'Asignado', fecha_asignacion: new Date().toISOString() });
                }
                showNotification("Territorios asignados");
                modal.remove();
                loadData();
            };
        });
    };

    window.handleBulkReturn = async () => {
        const assigned = _globalTerritorios.filter(t => t.estado === 'Asignado');
        if (assigned.length === 0) return showNotification("Nada que devolver", "info");

        showModal(`
            <div class="p-8 space-y-6">
                <h3 class="text-xl font-black uppercase">Informar Territorios Completados</h3>
                <div class="space-y-2 max-h-96 overflow-y-auto">
                    ${assigned.map(t => `
                        <label class="flex items-center gap-4 p-4 bg-slate-50 dark:bg-white/5 rounded-xl cursor-pointer">
                            <input type="checkbox" class="ret-check" value="${t.id}">
                            <span class="text-sm font-bold uppercase">#${t.numero} - ${t.asignado_a}</span>
                        </label>
                    `).join('')}
                </div>
                <button id="btn-confirm-ret" class="w-full py-4 bg-emerald-500 text-white rounded-xl font-black uppercase tracking-widest">Confirmar como Completados</button>
            </div>
        `, (modal) => {
            modal.querySelector('#btn-confirm-ret').onclick = async () => {
                const ids = Array.from(modal.querySelectorAll('.ret-check:checked')).map(i => i.value);
                for (const id of ids) await returnTerritorio(id, "Completado masivo", new Date().toISOString(), "Completado");
                showNotification("Territorios marcados como completados");
                modal.remove();
                loadData();
            };
        });
    };

    await loadData();
};

import Chart from 'chart.js/auto';
import {
    getHistorialReport, getConductores, getTerritorios, getPublicadores, getConfiguracion,
    assignTerritorio, returnTerritorio, transferTerritory, addHistoryRecord, updateHistoryRecord, deleteHistoryRecord, updateTerritorio,
    getProgramaSemanal, getGlobalObservations
} from '../../data/firestore-services.js';
import { UIHelpers, showModal, showCustomConfirm, showCustomPrompt, showTerritorySelectionModal } from '../services/ui-helpers.js';
import { formatPhoneNumber, getStatusColor, showNotification } from '../utils/helpers.js';

const { formatDisplayDateRange } = UIHelpers;

export const renderHistorialView = async (container) => {
    const monday = UIHelpers.getMonday(new Date());
    const weekId = UIHelpers.formatDateId(monday);

    const [history, tRaw, allPublicadores, currentProg] = await Promise.all([
        getHistorialReport(),
        getTerritorios(),
        getPublicadores(),
        getProgramaSemanal(weekId).catch(() => null)
    ]);

    // Extract territory numbers from the current program to ensure they appear in Historial
    const programTerritories = new Set();
    if (currentProg && currentProg.dias) {
        currentProg.dias.forEach(d => {
            ['manana', 'tarde', 'noche', 'zoom'].forEach(turn => {
                if (d[turn] && d[turn].territorio) {
                    String(d[turn].territorio).split(/[,;/]/).forEach(n => {
                        const clean = String(n || '').trim();
                        if (clean) programTerritories.add(clean);
                    });
                }
            });
        });
    }

    // Force re-import if needed for repair
    const { runSystemDiagnosticsAndRepair } = await import('../../data/firestore-services.js');

    // Xolvy Data Shield: Unique numbers only (Removed 1-22 restriction to support all territories)
    const normalizeT = (val) => String(val || '').trim();
    const seen = new Set();
    const allTerritorios = tRaw
        .filter(rec => {
            const numStr = normalizeT(rec.numero);
            if (!numStr) return false;
            if (seen.has(numStr)) return false;
            seen.add(numStr);
            return true;
        })
        .map(rec => ({
            ...rec,
            numero: normalizeT(rec.numero),
            manzanas: String(rec.manzanas || '').replace(/Salmo/gi, 'Mz.').trim()
        }))
        .sort((a, b) => a.numero.localeCompare(b.numero, undefined, { numeric: true, sensitivity: 'base' }));

    // Build ID to Num mapping for robust history linking
    const idToNum = {};
    allTerritorios.forEach(t => idToNum[t.id] = t.numero);

    // Group history by territory number for easy access (Robust Normalization & Multi-Territory Support)
    const historyByNum = history.reduce((acc, h) => {
        // Support for multi-territory records (e.g., "1 / 2" or "15, 16")
        // FALLBACK: If numero is missing, use ID mapping
        let rawNum = String(h.numero || '');
        if (!rawNum && h.territorio_id && idToNum[h.territorio_id]) {
            rawNum = idToNum[h.territorio_id];
        }

        const nums = rawNum.split(/[,/]/).map(s => normalizeT(s)).filter(Boolean);

        nums.forEach(num => {
            if (!acc[num]) acc[num] = [];
            acc[num].push({ ...h, numero: num });
        });
        return acc;
    }, {});

    // Helper to extract a sortable value from different date formats
    const getSortableDate = (h) => {
        const d = h.timestamp || h.fecha_entrega || h.fecha_asignacion;
        if (!d) return 0;
        const date = d.toDate ? d.toDate() : new Date(d);
        return isNaN(date.getTime()) ? 0 : date.getTime();
    };

    // Stats recalculation (radar)
    const assignedCount = allTerritorios.filter(t => t.estado === 'Asignado').length;
    const coverage = allTerritorios.length > 0 ? Math.round((assignedCount / allTerritorios.length) * 100) : 0;

    container.innerHTML = `
        <div class="relative animate-fade-in p-2 md:p-4 max-w-7xl mx-auto w-full overflow-x-hidden pb-20">
            <!-- Stats Bar (Xolvy Radar) -->
            <div class="flex flex-wrap justify-end gap-2 mb-6 pointer-events-none">
                <div class="pointer-events-auto bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border border-slate-200 dark:border-white/10 px-4 py-2.5 rounded-2xl shadow-sm flex items-center gap-3">
                    <div class="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
                    <span class="text-[9px] font-black uppercase text-slate-500 dark:text-slate-400 tracking-wider">${coverage}% Cobertura</span>
                </div>
                <div class="pointer-events-auto bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border border-slate-200 dark:border-white/10 px-4 py-2.5 rounded-2xl shadow-sm flex items-center gap-3">
                    <div class="w-1.5 h-1.5 rounded-full bg-rose-500"></div>
                    <span class="text-[9px] font-black uppercase text-slate-500 dark:text-slate-400 tracking-wider">${assignedCount} Ocupados</span>
                </div>
            </div>

            <header class="flex flex-col md:flex-row justify-between items-center gap-4 mb-8">
                <div class="relative group w-full md:w-96">
                    <span class="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-primary transition-colors cursor-default"><i class="fas fa-search text-xs"></i></span>
                    <input type="text" id="hist-search" placeholder="Filtrar actividad..." class="w-full bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-2xl !pl-12 pr-6 py-3.5 text-[12px] font-bold shadow-sm outline-none focus:border-primary transition-all text-slate-700 dark:text-white">
                </div>
                <div class="flex items-center gap-3 w-full md:w-auto">
                    <button id="btn-global-obs" class="flex-1 md:flex-none h-12 px-6 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl text-[9px] font-black uppercase tracking-widest transition-all shadow-lg active:scale-95 flex items-center justify-center gap-3">
                        <i class="fas fa-comment-alt"></i> Bit├ícora
                    </button>
                    <button id="btn-manual-log" class="flex-1 md:flex-none h-12 px-6 bg-teal-600 hover:bg-teal-500 text-white rounded-xl text-[9px] font-black uppercase tracking-widest transition-all shadow-lg active:scale-95 flex items-center justify-center gap-3">
                        <i class="fas fa-file-signature"></i> Cargar Manual
                    </button>
                    <select id="hist-filter-status" class="flex-1 md:flex-none h-12 bg-white dark:bg-white/5 border border-slate-200 dark:border-white/10 rounded-xl px-4 text-[9px] font-black uppercase text-slate-500 outline-none focus:border-primary transition-all cursor-pointer">
                        <option value="">TODOS</option>
                        <option value="Asignado">Asignados</option>
                        <option value="Disponible">Libres</option>
                    </select>
                    <button id="btn-sync-history" class="w-12 h-12 bg-slate-100 dark:bg-white/5 text-slate-400 hover:text-emerald-500 rounded-xl border border-slate-200 dark:border-white/10 transition-all flex items-center justify-center group" title="Sincronizar todo el historial">
                        <i class="fas fa-sync-alt group-hover:rotate-180 transition-transform duration-700"></i>
                    </button>
                </div>
            </header>

            <!-- List Section -->
            <div class="space-y-4">
                <div id="unified-control-grid" class="space-y-3">
                    <!-- Dynamic Grid -->
                </div>
            </div>
        </div>

        <div id="modal-container-nested" class="hidden"></div>
    `;

    const grid = container.querySelector('#unified-control-grid');
    const searchInp = container.querySelector('#hist-search');
    const statusFilter = container.querySelector('#hist-filter-status');
    const syncBtn = container.querySelector('#btn-sync-history');

    if (syncBtn) {
        syncBtn.onclick = async () => {
            const icon = syncBtn.querySelector('i');
            icon.classList.add('fa-spin');
            syncBtn.disabled = true;

            try {
                await runSystemDiagnosticsAndRepair((msg, pc) => {
                    showNotification(`ÔÜí Sincronizando: ${msg}`, 'info');
                });
                showNotification("┬íHistorial reconstruido con ├®xito!", "success");
                // Re-render everything
                renderHistorialView(container);
            } catch (e) {
                showNotification("Error en sincronizaci├│n: " + e.message, "error");
            } finally {
                icon.classList.remove('fa-spin');
                syncBtn.disabled = false;
            }
        };
    }

    const renderGrid = () => {
        const query = searchInp.value.toLowerCase().trim();
        const status = statusFilter.value;

        let displayList = allTerritorios
            .filter(t => {
                const n = (t.numero || '').toLowerCase();
                const matchesQuery = n.includes(query) ||
                    (t.asignado_a && t.asignado_a.toLowerCase().includes(query)) ||
                    (t.localidad && t.localidad.toLowerCase().includes(query));

                // --- RELEVANCE FILTER ---
                // Show if: Currently assigned, has completion history, is in current Program, or user is searching
                const tNumKey = String(t.numero || '');
                const isAsignado = t.estado === 'Asignado' || (t.asignado_a && t.asignado_a.trim() !== '');
                const hasHistory = (historyByNum[tNumKey] || []).length > 0;
                const inProgram = programTerritories.has(tNumKey);

                const isRelevant = isAsignado || hasHistory || inProgram || query.length > 0;

                const matchesStatus = !status || t.estado === status;
                return matchesQuery && matchesStatus && isRelevant;
            })
            .sort((a, b) => (a.numero || '').localeCompare(b.numero || '', undefined, { numeric: true }));

        if (displayList.length === 0) {
            grid.innerHTML = `<div class="py-20 text-center opacity-30 text-[10px] font-black uppercase tracking-widest">Sin registros encontrados</div>`;
            return;
        }

        grid.innerHTML = displayList.map(t => {
            const tNumKey = String(t.numero || '');
            const tHistory = (historyByNum[tNumKey] || [])
                .sort((a, b) => getSortableDate(b) - getSortableDate(a));

            const isFree = t.estado === 'Libre' || t.estado === 'Disponible' || t.estado === 'Sin asignar';
