        let history = [];

        try {
            const raw = await getTerritorios();
            // Xolvy Shield: Prevent duplicates by Number (Fix Terr 9 issue)
            const seen = new Set();
            terrs = raw.filter(t => {
                const n = String(t.numero);
                if (seen.has(n)) return false;
                seen.add(n);
                return true;
            });
            history = await getHistorialReport();
