                    }
                }

                content.style.transform = 'translateX(0px)';
                if (leftAction) leftAction.style.opacity = 0;
                if (rightAction) rightAction.style.opacity = 0;
                setTimeout(() => card.style.backgroundColor = 'transparent', 300);
                currentX = 0;
            });
        });
    }

