const renderReport = (parent, dataInRange, allHistory, allTerritorios, startDate, endDate, yearLabel, congregationName) => {
    const container = parent.querySelector('#report-preview');
    if (!container) return;
    container.innerHTML = '';

    // 1. Map all territories
    const territoriesMap = new Map();

    // Sort all territories numerically by number
    const sortedTerrs = [...allTerritorios].sort((a, b) =>
        String(a.numero).localeCompare(String(b.numero), undefined, { numeric: true })
    );

    sortedTerrs.forEach(t => {
        const numStr = String(t.numero).padStart(2, '0');
        if (!territoriesMap.has(numStr)) territoriesMap.set(numStr, []);
    });

    // Populate with assignments in range
    dataInRange.forEach(item => {
        if (!item.numero) return;
        const nums = item.numero.toString().split(/[,/]/).map(n => n.trim().padStart(2, '0'));
        nums.forEach(num => {
            if (territoriesMap.has(num)) {
                territoriesMap.get(num).push({ ...item, numero: num });
            }
        });
    });

    const sortedKeys = Array.from(territoriesMap.keys()).sort((a, b) =>
        a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );

    // 2. Pagination State (Image shows 22 rows per page)
    let pageHtmls = [];
    const TERR_PER_PAGE = 25;
    const ASSIGNS_PER_PAGE = 4;

    for (let i = 0; i < sortedKeys.length; i += TERR_PER_PAGE) {
        const terrChunkKeys = sortedKeys.slice(i, i + TERR_PER_PAGE);

        // Calculate Max Assignments across this chunk to see if we need multiple HORIZONTAL pages
        let maxAssigns = 0;
        terrChunkKeys.forEach(k => {
            const count = territoriesMap.get(k).length;
            if (count > maxAssigns) maxAssigns = count;
        });
        if (maxAssigns === 0) maxAssigns = 1;

        const sheetsNeeded = Math.ceil(maxAssigns / ASSIGNS_PER_PAGE);

        for (let s = 0; s < sheetsNeeded; s++) {
            const assignStartIndex = s * ASSIGNS_PER_PAGE;
            pageHtmls.push(S13Exporter.generatePageHtml(
                terrChunkKeys,
                territoriesMap,
                allHistory, // Pass all history to find "Last Completion"
                startDate,
                assignStartIndex,
                ASSIGNS_PER_PAGE,
                yearLabel,
                congregationName
            ));
        }
    }

    if (pageHtmls.length === 0) {
        container.innerHTML = `
            <div class="text-center mt-32 space-y-6 opacity-30">
                <div class="w-24 h-24 bg-slate-200 dark:bg-white/5 rounded-[2rem] flex items-center justify-center text-4xl mx-auto">
                    <i class="fas fa-folder-open"></i>
                </div>
                <p class="text-xs font-black uppercase tracking-[0.4em]">No hay asignaciones en este rango</p>
            </div>
        `;
        return;
    }

    container.innerHTML = pageHtmls.join('');
};

const formatDateShort = (isoStr) => {
    if (!isoStr) return '';
    const d = new Date(isoStr);
    return `${d.getDate()}/${d.getMonth() + 1}/${d.getFullYear()}`;
};

import * as dateFns from 'date-fns';

export const UIHelpers = {
    fmtDate: (d) => {
        if (!d) return '';
        const date = d.toDate ? d.toDate() : new Date(d);
        return isNaN(date.getTime()) ? 'ÔÇö' : date.toLocaleDateString('es-ES', { day: '2-digit', month: '2-digit' });
    },
    fmtDateAt: (d) => {
        if (!d) return '';
        const date = d.toDate ? d.toDate() : new Date(d);
        return isNaN(date.getTime()) ? 'ÔÇö' : date.toLocaleDateString('es-ES', { day: '2-digit', month: 'short' });
    },

    getMonday: (d) => {
        d = new Date(d);
        const day = d.getDay();
        const diff = d.getDate() - day + (day === 0 ? -6 : 1);
        return new Date(d.setDate(diff));
    },

    formatDateId: (date) => {
        const d = new Date(date);
        const year = d.getFullYear();
        const month = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        return `${year}-${month}-${day}`;
    },

    formatDisplayDateRange: (date) => {
        try {
            const start = new Date(date);
            if (isNaN(start.getTime())) return '';
            const end = new Date(date);
            end.setDate(start.getDate() + 6);
            if (dateFns) {
                return `${dateFns.format(start, 'd MMM')} - ${dateFns.format(end, 'd MMM yyyy')}`;
            }
            const f = (d) => `${d.getDate()}/${d.getMonth() + 1}`;
            return `${f(start)} - ${f(end)}, ${start.getFullYear()}`;
        } catch (e) { return date; }
    },

    initImagePanZoom: (imgId, containerId) => {
        const img = document.getElementById(imgId);
        const container = document.getElementById(containerId);
        if (!img || !container) return null;

        let state = { scale: 1, x: 0, y: 0 };
        let isDragging = false;
        let startX, startY;
        let lastX = 0, lastY = 0;
        let lastTouchDist = 0;

        const updateTransform = () => {
            img.style.transform = `scale(${state.scale}) translate(${state.x}px, ${state.y}px)`;
        };

        // Mouse Events
        container.onmousedown = (e) => {
            e.preventDefault();
            isDragging = true;
            startX = e.clientX - lastX;
            startY = e.clientY - lastY;
            container.style.cursor = 'grabbing';
        };

        window.onmousemove = (e) => {
            if (!isDragging) return;
            lastX = e.clientX - startX;
            lastY = e.clientY - startY;
            state.x = lastX / state.scale;
            state.y = lastY / state.scale;
            updateTransform();
        };

        window.onmouseup = () => {
            isDragging = false;
            container.style.cursor = 'default';
        };

        // Touch Events
        container.ontouchstart = (e) => {
            if (e.touches.length === 1) {
                isDragging = true;
                startX = e.touches[0].clientX - lastX;
                startY = e.touches[0].clientY - lastY;
            } else if (e.touches.length === 2) {
                lastTouchDist = Math.hypot(
                    e.touches[0].clientX - e.touches[1].clientX,
                    e.touches[0].clientY - e.touches[1].clientY
                );
            }
        };

        container.ontouchmove = (e) => {
            if (e.touches.length === 1 && isDragging) {
                lastX = e.touches[0].clientX - startX;
                lastY = e.touches[0].clientY - startY;
                state.x = lastX / state.scale;
                state.y = lastY / state.scale;
                updateTransform();
            } else if (e.touches.length === 2) {
                e.preventDefault(); // Prevent scroll while pinching
                const dist = Math.hypot(
                    e.touches[0].clientX - e.touches[1].clientX,
                    e.touches[0].clientY - e.touches[1].clientY
                );
                const delta = (dist - lastTouchDist) / 100;
                state.scale = Math.max(1, Math.min(10, state.scale + delta));
                lastTouchDist = dist;
                updateTransform();
            }
        };

        container.ontouchend = () => {
            isDragging = false;
        };

        // Wheel Zoom
        container.onwheel = (e) => {
            e.preventDefault();
            const delta = e.deltaY > 0 ? -0.2 : 0.2;
            state.scale = Math.max(1, Math.min(10, state.scale + delta));
            updateTransform();
        };

        return {
            reset: () => {
                state = { scale: 1, x: 0, y: 0 };
                lastX = 0; lastY = 0;
                updateTransform();
            },
            zoom: (delta) => {
                state.scale = Math.max(1, Math.min(10, state.scale + delta));
                updateTransform();
            }
        };
    }
};

export const showModal = (html, onRender, maxWidth = 'max-w-2xl', containerId = 'modal-container') => {
    const modal = document.getElementById(containerId);
    if (!modal) return;

    modal.innerHTML = `
        <div class="modal-backdrop-area absolute inset-0 cursor-default bg-slate-950/40 dark:bg-black/60 backdrop-blur-sm"></div>
        <div class="relative w-full ${maxWidth} max-h-[90vh] md:max-h-[85vh] flex flex-col bg-white dark:bg-[#0b0f1a]/95 backdrop-blur-2xl rounded-[3rem] shadow-[0_50px_100px_-20px_rgba(0,0,0,0.5)] border border-slate-200 dark:border-white/10 animate-scale-in overflow-hidden z-10 ring-1 ring-black/5 dark:ring-white/5">
            ${html}
        </div>
    `;

    modal.classList.remove('hidden');
    modal.classList.add('flex');

    if (onRender) onRender(modal);

    const close = () => {
        modal.classList.add('hidden');
        modal.classList.remove('flex');
        window.removeEventListener('keydown', handleEsc);
    };

    const handleEsc = (e) => {
        if (e.key === 'Escape') close();
    };
    window.addEventListener('keydown', handleEsc);

    modal.querySelector('.modal-backdrop-area').onclick = close;
};

