async function nuclearReset() {
    console.log("­ƒÜÇ Iniciando Reset Nuclear...");

    try {
        // 1. Respaldar territorios 1-22
        console.log("­ƒôª Respaldando territorios 1-22...");
        const terrSnap = await getDocs(collection(db, "territorios"));
        const backup = [];

        terrSnap.forEach(d => {
            const data = d.data();
            const numStr = String(data.numero || '');
            const num = parseInt(numStr);

            if (num >= 1 && num <= 22) {
                // Conservar solo lo esencial (Geograf├¡a y Metadatos)
                backup.push({
                    id: d.id,
                    numero: numStr,
                    manzanas: data.manzanas || '',
                    localidad: data.localidad || '',
                    geojson: data.geojson || null,
                    mapa_url: data.mapa_url || null,
                    puntos_interes: data.puntos_interes || []
                });
            }
        });
        console.log(`Ô£à Respaldo completado: ${backup.length} territorios encontrados.`);

        // 2. Funci├│n para borrar una colecci├│n completa
        const deleteCollection = async (colName) => {
            console.log(`­ƒùæ´©Å Borrando colecci├│n: ${colName}...`);
            const snap = await getDocs(collection(db, colName));
            let count = 0;
            const batch = writeBatch(db);
            snap.forEach(d => {
                batch.delete(d.ref);
                count++;
            });
            if (count > 0) await batch.commit();
            console.log(`Ô£à Colecci├│n ${colName} borrada (${count} documentos).`);
        };

        // 3. Ejecutar borrados
        await deleteCollection("historial_territorios");
        await deleteCollection("programa_semanal");
        await deleteCollection("territorios");

        // 4. Restaurar territorios 1-22 (Limpios)
        console.log("­ƒÅù´©Å Restaurando inventario base (1-22)...");
        const restoreBatch = writeBatch(db);
        backup.forEach(t => {
            const { id, ...cleanData } = t;
            const ref = doc(db, "territorios", id);
            restoreBatch.set(ref, cleanData);
        });
        await restoreBatch.commit();
        console.log("Ô£à Inventario 1-22 restaurado con ├®xito.");

        // 5. Inicializar colecciones nuevas (opcional, Firebase las crea al primer write)
        console.log("Ô£¿ Sistema listo para la nueva era unificada.");
        process.exit(0);

    } catch (e) {
        console.error("ÔØî ERROR CR├ìTICO DURANTE EL RESET:", e);
        process.exit(1);
    }
}

